    "cases.assess_and_price_a_variation.step.issue.what": "Zašlete oceněný změnový list klientovi nebo správci smlouvy podle smluvních podmínek, s výměrou a sazbami jako podkladem, a sledujte jej až k podepsané dohodě.",
    "cases.assess_and_price_a_variation.step.issue.why": "Změnový list, který je oceněn, ale nikdy formálně vydán, je práce, kterou jste udělali zadarmo. Jeho písemné odsouhlasení je to, co změní změnu na proplacený náklad místo pohlcené ztráty.",
    "cases.assess_and_price_a_variation.step.price.in.change": "Zaevidovaný změnový list",
    "cases.assess_and_price_a_variation.step.price.in.measure": "Přidané a vypuštěné práce",
    "cases.assess_and_price_a_variation.step.price.in.rates": "Smluvní sazby BOQ",
    "cases.assess_and_price_a_variation.step.price.out.breakdown": "Oceněný rozpad",
