    "cases.assess_and_price_a_variation.step.price.title": "Oceňte přidané a vypuštěné práce",
    "cases.assess_and_price_a_variation.step.price.what": "Změřte přidané a vypuštěné práce a oceňte obojí podle svých sazeb BOQ, aby změnový list ukazoval čistou částku postavenou na stejných sazbách, na kterých byla zakázka získána.",
    "cases.assess_and_price_a_variation.step.price.why": "Ocenit změnu podle dohodnutých sazeb a ocenit vypuštění stejně poctivě jako přidání je to, co udrží změnový list obhajitelný a nechá jej odsouhlasit bez hádky o vymyšlená čísla.",
    "cases.assess_and_price_a_variation.step.report.in.agreed": "Odsouhlasený změnový list",
    "cases.assess_and_price_a_variation.step.report.in.changes": "Evidence změnových listů",
    "cases.assess_and_price_a_variation.step.report.in.sum": "Smluvní cena",
    "cases.assess_and_price_a_variation.step.report.out.report": "Zpráva o stavu změn",
