    "cases.change_register_and_impact.step.register.out.value": "Zaevidovaný stav a hodnota",
    "cases.change_register_and_impact.step.register.title": "Zaevidujte změnu",
    "cases.change_register_and_impact.step.register.what": "Zaznamenejte každou změnu, jak přijde, s jejím původem, aktuálním stavem a hodnotou do jednoho registru, aby žádný pokyn nepřežíval jen jako řádek pohřbený v e-mailovém vláknu.",
    "cases.change_register_and_impact.step.register.why": "Změna, která se nikdy nedostala do registru, je změna, za kterou vám nezaplatí. Jeden sdílený seznam je to, co promění rozptýlené ústní pokyny a poznámky ze stavby na nárokovatelnou, auditovatelnou pozici.",
    "cases.change_register_and_impact.step.report.in.forecast": "Prognóza konečného vyúčtování",
    "cases.change_register_and_impact.step.report.in.impact": "Vyhodnocený dopad změn",
    "cases.change_register_and_impact.step.report.out.report": "Zpráva o změnách pro klienta",
    "cases.change_register_and_impact.step.report.out.trend": "Kumulativní trend",
    "cases.change_register_and_impact.step.report.title": "Vykažte trend",
    "cases.change_register_and_impact.step.report.what": "Vytvořte zprávu o změnách, která ukazuje kumulativní hodnotu k dnešnímu dni, rozdělení otevřených oproti odsouhlaseným a o kolik každá položka posouvá prognózu konečného vyúčtování.",
    "cases.change_register_and_impact.step.report.why": "Klient přijme trend změn, jehož narůstání sledoval; bojuje proti tomu, který na něj spadne u konečného vyúčtování. Vykazovat včas a srozumitelně je to, co udrží ten poslední rozhovor klidný.",
    "cases.change_register_and_impact.title": "Registr změn a jejich dopad",
    "cases.change_to_paid_variation.desc": "Zachyťte změnu rozsahu, dokud je čerstvá, oceňte ji jako smluvní změnový list podle dohodnutých sazeb a vyúčtujte v další žádosti o platbu, aby byly vícepráce proplaceny, ne tiše pohlceny.",
    "cases.change_to_paid_variation.step.change.in.instruction": "Pokyn na stavbě",
    "cases.change_to_paid_variation.step.change.in.revision": "Revize výkresu",
    "cases.change_to_paid_variation.step.change.out.impact": "Dopad na čas a náklady",
    "cases.change_to_paid_variation.step.change.out.record": "Záznam o změně",
    "cases.change_to_paid_variation.step.change.title": "Založte změnu",
    "cases.change_to_paid_variation.step.change.what": "Zapište přesně, co se změnilo, kdo to nařídil a která revize výkresu nebo pokyn na stavbě to vyvolaly. Poznamenejte si pravděpodobný dopad na čas a náklady hned, dokud máte četu a fakta ještě před sebou.",
    "cases.change_to_paid_variation.step.change.why": "Změna zaznamenaná v den, kdy nastane, je změna, kterou můžete doložit a nechat proplatit. Ty, které tým prostě odpracuje bez poznámky, jsou ty, které ukousnou marži a nic za to není vidět.",
    "cases.change_to_paid_variation.step.claim.in.measured": "Změřená provedená práce",
    "cases.change_to_paid_variation.step.claim.in.variation": "Nařízený změnový list",
    "cases.change_to_paid_variation.step.claim.out.certified": "Certifikovaná platba",
    "cases.change_to_paid_variation.step.claim.out.claim": "Žádost o platbu",
    "cases.change_to_paid_variation.step.claim.title": "Vyúčtujte v žádosti o platbu",
    "cases.change_to_paid_variation.step.claim.what": "Zahrňte nařízený změnový list do další žádosti o platbu podle smlouvy, aby byl certifikován a fakturován spolu se změřenou prací, ne aby zůstal ležet na seznamu dlužných věcí.",
    "cases.change_to_paid_variation.step.claim.why": "Oceněný a nařízený vám stále nic nevydělá, dokud není vyfakturován a certifikován. Zahrnutí změnového listu do žádosti o platbu je krok, který konečně promění odsouhlasené vícepráce na peníze na účtu.",
    "cases.change_to_paid_variation.step.variation.in.change": "Záznam o změně",
