    "cases.change_to_paid_variation.step.variation.out.instruction": "Pokyn klienta",
    "cases.change_to_paid_variation.step.variation.out.variation": "Oceněný změnový list",
    "cases.change_to_paid_variation.step.variation.title": "Oceňte jako změnový list",
    "cases.change_to_paid_variation.step.variation.what": "Povyšte změnu na formální smluvní změnový list, oceňte přidané a vypuštěné práce položku po položce podle svých dohodnutých nebo nově dojednaných sazeb a poté ji odešlete k pokynu klienta, který ji schválí.",
    "cases.change_to_paid_variation.step.variation.why": "Změnový list je místo, kde se změna stává smluvním nárokem, ne laskavostí. Postavit cenu z dohodnutých sazeb je to, co jí umožní obstát, když ji rozpočtář zpochybní.",
    "cases.change_to_paid_variation.title": "Přeměna změny na proplacený změnový list",
    "cases.compare_bids_and_award.desc": "Vezměte složku vrácených nabídek, které si nikdy úplně neodpovídají, srovnejte je na stejný rozsah a předejte klientovi rozhodnutí o zadání, které obstojí při prověření.",
    "cases.compare_bids_and_award.step.award.in.coverage": "Pokrytí rozsahu",
