    "cases.compare_bids_and_award.step.level.out.gaps": "Označené mezery v rozsahu",
    "cases.compare_bids_and_award.step.level.out.levelled": "Srovnané porovnání nabídek",
    "cases.compare_bids_and_award.step.level.title": "Srovnejte nabídky",
    "cases.compare_bids_and_award.step.level.what": "Rozložte nabídky sloupec po sloupci a poté vraťte každou výhradu, výluku a rezervní částku zpět do ceny, aby se jednotkové sazby daly porovnat mezi sebou. Označte mezery, kde uchazeč prostě rozsah vynechal.",
    "cases.compare_bids_and_award.step.level.why": "Nejnižší úvodní číslo často patří tomu, kdo zapomněl nejvíc. Jakmile se doplní chybějící pomocné práce a předpoklady práce v režii, skutečně nejvýhodnější nabídka je obvykle jiná.",
    "cases.compare_bids_and_award.step.open.in.bids": "Vrácené nabídky",
