    "cases.compare_bids_and_award.step.open.in.schedule": "Vydaný soupis k ocenění",
    "cases.compare_bids_and_award.step.open.out.baseline": "Potvrzený společný základ",
    "cases.compare_bids_and_award.step.open.out.verified": "Ověřený seznam uchazečů",
