    "cases.compile_weekly_progress_report.step.actuals.out.slippage": "Skluz oproti výchozímu plánu",
    "cases.compile_weekly_progress_report.step.actuals.title": "Aktualizujte postup v harmonogramu",
    "cases.compile_weekly_progress_report.step.actuals.what": "Projděte harmonogram a nastavte skutečné procento dokončení u každé aktivní úlohy, vyznačte, co tento týden začalo a skončilo, a nechte jej ukázat skluz oproti výchozímu plánu, místo aby jej skrýval.",
    "cases.compile_weekly_progress_report.step.actuals.why": "Zpráva postavená na zbožných procentech nikoho dlouho neošálí a zničí vaši důvěryhodnost, když pravda vyjde najevo. Poctivé skutečnosti teď jsou to, co učiní datum dokončení, které uvádíte, uvěřitelným.",
    "cases.compile_weekly_progress_report.step.diary.in.entries": "Denní záznamy ze stavebního deníku",
    "cases.compile_weekly_progress_report.step.diary.in.photos": "Fotografie ze stavby",
    "cases.compile_weekly_progress_report.step.diary.out.counts": "Počty pracovníků a mechanizace",
    "cases.compile_weekly_progress_report.step.diary.out.evidence": "Datovaný balíček důkazů",
    "cases.compile_weekly_progress_report.step.diary.title": "Vytáhněte týdenní důkazy",
    "cases.compile_weekly_progress_report.step.diary.what": "Shromážděte denní záznamy z deníku, počty pracovníků a mechanizace, počasí a fotografie ze stavby za daný týden, aby postup, který vykazujete, byl podložen datovaným záznamem toho, co se na stavbě skutečně stalo.",
    "cases.compile_weekly_progress_report.step.diary.why": "Číslo bez důkazů je jen názor, který klient může zpochybnit. Deník a fotografie jsou také souběžný záznam, který má váhu, pokud se o měsíce později řeší nárok ze zpoždění.",
    "cases.compile_weekly_progress_report.step.publish.in.evidence": "Balíček důkazů",
    "cases.compile_weekly_progress_report.step.publish.in.lookahead": "Výhled",
    "cases.compile_weekly_progress_report.step.publish.in.progress": "Aktualizovaný postup",
    "cases.compile_weekly_progress_report.step.publish.out.asks": "Úkoly pro klienta a rizika",
    "cases.compile_weekly_progress_report.step.publish.out.report": "Týdenní zpráva o postupu",
    "cases.compile_weekly_progress_report.step.publish.title": "Zveřejněte zprávu",
    "cases.compile_weekly_progress_report.step.publish.what": "Sloučte postup, klíčové fotografie a výhled do jedné zprávy, upozorněte na rizika a na pomoc, kterou od klienta potřebujete, a vydávejte ji každý týden ve stejný den.",
    "cases.compile_weekly_progress_report.step.publish.why": "Zpráva, která vždy přijde ve stejný den, čte se přímočaře a upozorňuje na problémy včas, je to, co buduje důvěru, díky níž se rychle rozhoduje. Opožděná, přikrášlená zpráva dělá pravý opak.",
    "cases.compile_weekly_progress_report.title": "Sestavení týdenní zprávy o postupu",
    "cases.control_cost_against_budget.desc": "Udržte zakázku na jejím čísle: zafixujte oceněný výkaz jako rozpočtový základ, sledujte oproti němu zasmluvněné a skutečné výdaje profesi po profesi a vykazujte odchylku, dokud je ještě čas jednat.",
    "cases.control_cost_against_budget.step.baseline.in.bill": "Odsouhlasený oceněný výkaz",
    "cases.control_cost_against_budget.step.baseline.in.codes": "Struktura nákladových kódů",
    "cases.control_cost_against_budget.step.baseline.out.baseline": "Pevný rozpočtový základ",
    "cases.control_cost_against_budget.step.baseline.out.lines": "Rozpočtové položky po profesích",
    "cases.control_cost_against_budget.step.baseline.title": "Nastavte rozpočtový základ",
    "cases.control_cost_against_budget.step.baseline.what": "Vezměte odsouhlasený oceněný výkaz a zafixujte jej jako nákladový rozpočet, rozdělený po profesích nebo nákladových kódech, aby každý pozdější závazek a faktura měly cílovou položku, oproti které se měří.",
    "cases.control_cost_against_budget.step.baseline.why": "Výdaje nelze řídit bez pevné hranice, oproti které je řídíte, a rozpočet, který se stále posouvá, skrývá překročení stejně rychle, jak se objevují. Uzamčení základu je to, co dává odchylce smysl.",
    "cases.control_cost_against_budget.step.track.in.baseline": "Rozpočtový základ",
    "cases.control_cost_against_budget.step.track.in.invoices": "Faktury a záznamy ze stavby",
    "cases.control_cost_against_budget.step.track.in.orders": "Objednávky a subdodávky",
    "cases.control_cost_against_budget.step.track.out.actual": "Skutečné náklady",
    "cases.control_cost_against_budget.step.track.out.committed": "Zasmluvněné náklady",
    "cases.control_cost_against_budget.step.track.title": "Sledujte zasmluvněné a skutečné",
    "cases.control_cost_against_budget.step.track.what": "Zapisujte objednávky a subdodávky jako zasmluvněné náklady a faktury a záznamy ze stavby jako skutečné náklady, každé k jeho rozpočtové položce, abyste viděli rozpočet, zasmluvněné a utracené vedle sebe.",
    "cases.control_cost_against_budget.step.track.why": "Zasmluvněné náklady jsou překročení, které jste už podepsali, ale ještě nezaplatili, a právě tam zakázky tiše přejdou dřív, než dorazí jediná faktura. Jejich sledování, ne jen skutečností, je to, co vám dá skutečné varování.",
    "cases.control_cost_against_budget.step.variance.in.budget": "Rozpočtový základ",
    "cases.control_cost_against_budget.step.variance.in.spend": "Zasmluvněné a skutečné náklady",
    "cases.control_cost_against_budget.step.variance.out.forecast": "Prognóza konečných nákladů",
    "cases.control_cost_against_budget.step.variance.out.report": "Zpráva o nákladové odchylce",
    "cases.control_cost_against_budget.step.variance.title": "Vykažte odchylku",
    "cases.control_cost_against_budget.step.variance.what": "Vytvořte nákladovou zprávu ukazující rozpočet oproti zasmluvněným a skutečným s prognózou konečných nákladů po profesích a označte položky směřující k překročení, aby na ně tým mohl jmenovitě zareagovat.",
    "cases.control_cost_against_budget.step.variance.why": "Překročení zachycené ve čtvrtém měsíci lze ještě usměrnit přepracováním rozsahu nebo novým vyjednáváním; stejné číslo nalezené u konečného vyúčtování je jen ztráta, kterou je třeba vysvětlit. Vykazovat odchylku včas je celý smysl řízení nákladů.",
    "cases.control_cost_against_budget.title": "Řízení nákladů oproti rozpočtu",
    "cases.coordinate_and_resolve_model_clashes.desc": "Proveďte kolo koordinace kolizí: federujte modely jednotlivých profesí, detekujte kolize, roztřiďte a přiřaďte ty skutečné, vzneste projekční otázky, které vyvolávají, a potvrďte jejich vyřešení v další verzi modelu.",
    "cases.coordinate_and_resolve_model_clashes.step.confirm.in.answers": "Odpovědi na RFI",
