    "cases.coordinate_and_resolve_model_clashes.step.federate.out.aligned": "Modely s ověřenou revizí",
    "cases.coordinate_and_resolve_model_clashes.step.federate.out.federated": "Federovaná sada modelů",
    "cases.coordinate_and_resolve_model_clashes.step.federate.title": "Federujte modely profesí",
    "cases.coordinate_and_resolve_model_clashes.step.federate.what": "Spojte nejnovější modely architektury, konstrukce a TZB do jedné federované sady na sdíleném počátku projektu a před jakýmkoli testováním potvrďte, že každá profese je v aktuální revizi.",
    "cases.coordinate_and_resolve_model_clashes.step.federate.why": "Výsledky kolizí jsou jen tak dobré jako modely za nimi. Koordinace oproti zastaralému nebo špatně umístěnému modelu promarní celé kolo honěním konfliktů, které jsou už opravené nebo ve skutečnosti neexistují.",
    "cases.coordinate_and_resolve_model_clashes.step.raise.in.clashes": "Kolize blokující projekt",
    "cases.coordinate_and_resolve_model_clashes.step.raise.in.viewpoint": "Pohled v modelu",
    "cases.coordinate_and_resolve_model_clashes.step.raise.out.record": "Dohledatelná projekční otázka",
    "cases.coordinate_and_resolve_model_clashes.step.raise.out.rfi": "Vznesené RFI",
    "cases.coordinate_and_resolve_model_clashes.step.raise.title": "Vzneste projekční otázky",
    "cases.coordinate_and_resolve_model_clashes.step.raise.what": "Tam, kde kolize vyžaduje projekční rozhodnutí, ne pouhý přesun, vzneste ji jako RFI na vedoucího projektu, aby byla odpověď zapsaná, datovaná a dohledatelná zpět k pohledu v modelu.",
    "cases.coordinate_and_resolve_model_clashes.step.raise.why": "Některé kolize nemůže uzavřít koordinátor sám, vyžadují skutečné projekční rozhodnutí. Jejich formální vznesení znamená, že rozhodnutí je zaznamenáno a následná změna modelu je dohledatelná k jejímu důvodu.",
    "cases.coordinate_and_resolve_model_clashes.step.triage.in.model": "Pohled ve 3D modelu",
    "cases.coordinate_and_resolve_model_clashes.step.triage.in.owners": "Vlastníci profesí",
