    "cases.crew_and_plant_lookahead_balance.step.check.out.gaps": "Seznam nedostatku zdrojů",
    "cases.crew_and_plant_lookahead_balance.step.check.title": "Zkontrolovat, co je skutečně rezervované",
    "cases.crew_and_plant_lookahead_balance.step.check.what": "Porovnejte hodiny a mechanizaci rezervované na stavbě s tím, co požaduje výhledový plán, a označte profese, kterým bude scházet kapacita, ještě než týden začne.",
    "cases.crew_and_plant_lookahead_balance.step.check.why": "Rezervované hodiny jsou skutečný obraz toho, co na stavbu opravdu dorazí. Odhalit nedostatek týden předem znamená jeden telefonát, odhalit ho v den nasazení znamená stojící partu.",
    "cases.crew_and_plant_lookahead_balance.step.close.in.available": "Dostupné čety a mechanizace",
    "cases.crew_and_plant_lookahead_balance.step.close.in.gaps": "Seznam nedostatku zdrojů",
    "cases.crew_and_plant_lookahead_balance.step.close.out.lookahead": "Výhledový plán se zajištěnými zdroji",
    "cases.crew_and_plant_lookahead_balance.step.close.out.report": "Zpráva o zajištění zdrojů",
    "cases.crew_and_plant_lookahead_balance.step.close.title": "Zacelit mezeru a vykázat ji",
    "cases.crew_and_plant_lookahead_balance.step.close.what": "Zajistěte navíc čety, mechanizaci nebo přesčasy potřebné k pokrytí mezery a vykažte výhledový plán se zajištěnými zdroji, aby širší tým viděl, že je plán řádně zdrojově pokrytý, ne jen naplánovaný v čase.",
    "cases.crew_and_plant_lookahead_balance.step.close.why": "Výhledový plán s termíny, ale bez zajištěných zdrojů, je jen seznam přání. Ukázat, že je zdrojově pokrytý, je to, co dělá plán věrohodným pro profese, které ho mají realizovat.",
    "cases.crew_and_plant_lookahead_balance.step.read.in.programme": "Harmonogram projektu",
    "cases.crew_and_plant_lookahead_balance.step.read.in.window": "Výhledové okno",
    "cases.crew_and_plant_lookahead_balance.step.read.out.demand": "Potřeba čet a mechanizace",
    "cases.crew_and_plant_lookahead_balance.step.read.out.needs": "Potřeby po jednotlivých profesích",
    "cases.crew_and_plant_lookahead_balance.step.read.title": "Zjistit krátkodobou potřebu",
    "cases.crew_and_plant_lookahead_balance.step.read.what": "Projděte činnosti na harmonogramu na několik následujících týdnů a u každé si poznamenejte profesi, velikost čety a případnou mechanizaci, kterou potřebuje, aby běžela podle plánu.",
    "cases.crew_and_plant_lookahead_balance.step.read.why": "Úkol, ke kterému není rezervovaná četa ani jeřáb, je úkol, který v den daný harmonogramem nezačne.",
    "cases.crew_and_plant_lookahead_balance.title": "Vyvážení čet a mechanizace v rámci harmonogramu",
    "cases.defects_liability_period_tracking.desc": "Jakmile je budova užívaná, zaznamenejte každou nahlášenou vadu k dodavateli a termínu odstranění a dotáhněte seznam na nulu dřív, než záruční doba skončí.",
    "cases.defects_liability_period_tracking.step.assign.in.clause": "Ustanovení o vadách",
    "cases.defects_liability_period_tracking.step.assign.in.defect": "Zaznamenaná vada",
    "cases.defects_liability_period_tracking.step.assign.out.due": "Stanovený termín",
    "cases.defects_liability_period_tracking.step.assign.out.owner": "Přiřazený dodavatel",
    "cases.defects_liability_period_tracking.step.assign.title": "Přiřadit a stanovit termín",
    "cases.defects_liability_period_tracking.step.assign.what": "Přiřaďte položku dodavateli, který je podle ustanovení o vadách povinen ji odstranit, stanovte termín v rámci záruční doby a sledujte ji, dokud není označená za vyřešenou.",
    "cases.defects_liability_period_tracking.step.assign.why": "Záruční doba má pevný konec a vada, která je při jejím uplynutí stále otevřená, se stává nákladem, který nese vlastník. Přiřazení a otermínování každé z nich je to, co udržuje povinnost vymahatelnou.",
    "cases.defects_liability_period_tracking.step.close.in.list": "Seznam uzavřených vad",
    "cases.defects_liability_period_tracking.step.close.in.retention": "Zadržené zádržné",
    "cases.defects_liability_period_tracking.step.close.out.certificate": "Závěrečné osvědčení",
    "cases.defects_liability_period_tracking.step.close.out.retention": "Uvolněné zádržné",
    "cases.defects_liability_period_tracking.step.close.title": "Uzavřít období načisto",
