    "cases.issue_a_controlled_drawing_revision.step.register.out.superseded": "Starý výkres nahrazen",
    "cases.issue_a_controlled_drawing_revision.step.register.title": "Zaevidovat novou revizi",
    "cases.issue_a_controlled_drawing_revision.step.register.what": "Nahrajte novou revizi do registru dokumentů s jejím číslem, datem a písmenem revize, označte předchozí verzi jako nahrazenou a poznamenejte, co se změnilo, aby čtenář věděl, proč se výkres posunul.",
    "cases.issue_a_controlled_drawing_revision.step.register.why": "Dvě platné kopie stejného výkresu jsou příčinou, proč se stěna postaví podle geometrie z minulého měsíce. Jeden řízený registr s jasně vyřazenou starou revizí je to, co nenechá pochyb, který výkres platí.",
    "cases.issue_a_controlled_drawing_revision.step.transmit.in.recipients": "Distribuční seznam profesí",
    "cases.issue_a_controlled_drawing_revision.step.transmit.in.revision": "Zaevidovaná revize",
    "cases.issue_a_controlled_drawing_revision.step.transmit.out.record": "Záznam o doručení",
    "cases.issue_a_controlled_drawing_revision.step.transmit.out.transmittal": "Vydaný průvodní list",
    "cases.issue_a_controlled_drawing_revision.step.transmit.title": "Rozeslat profesím",
    "cases.issue_a_controlled_drawing_revision.step.transmit.what": "Pošlete průvodní list každé profesi a subdodavateli, kteří podle toho výkresu pracují, s uvedením vydané revize a data, a uchovejte záznam o tom, komu a kdy byl odeslán.",
    "cases.issue_a_controlled_drawing_revision.step.transmit.why": "Revize, která leží v registru, ale nikdy se nedostane k partě, která betonuje desku, nezmění nic. Záznam o průvodním listu je zároveň vaším důkazem, že profese měla při realizaci aktuální informace.",
    "cases.issue_a_controlled_drawing_revision.step.verify.in.current": "Nejnovější revize",
    "cases.issue_a_controlled_drawing_revision.step.verify.in.posted": "Výkresy na pracovišti",
    "cases.issue_a_controlled_drawing_revision.step.verify.out.confirmed": "Aktuální výkres potvrzen",
    "cases.issue_a_controlled_drawing_revision.step.verify.out.removed": "Nahrazené výkresy staženy",
    "cases.issue_a_controlled_drawing_revision.step.verify.title": "Ověřit aktuální výkres na stavbě",
    "cases.issue_a_controlled_drawing_revision.step.verify.what": "Při obchůzce zkontrolujte, že výkresy vyvěšené na pracovišti a v buňkách profesí nesou nejnovější revizi, a stáhněte každý nahrazený výkres, který ještě najdete v používání.",
    "cases.issue_a_controlled_drawing_revision.step.verify.why": "Nahrazený výkres ponechaný na zdi dál staví starý detail bez ohledu na to, jak čistý máte registr. Jeho odstranění přímo u zdroje je nejlevnější vada, které kdy předejdete.",
    "cases.issue_a_controlled_drawing_revision.title": "Vydání řízené revize výkresu",
    "cases.issue_a_permit_to_work.desc": "Vystavte povolení k práci, navažte ho na jeho bezpečný pracovní postup a v záznamu ho uzavřete.",
    "cases.issue_a_permit_to_work.step.close-out.in.permit": "Aktivní povolení",
    "cases.issue_a_permit_to_work.step.close-out.in.workers": "Pracovníci na úkolu",
