    "cases.maintain_supplier_catalogs_and_buy_from_them.step.catalogs.out.rates": "Aktuální nákupní ceny",
    "cases.maintain_supplier_catalogs_and_buy_from_them.step.catalogs.title": "Naimportovat a aktualizovat katalogy dodavatelů",
