    "cases.payment_application_and_reconciliation.step.contract.out.sum": "Potvrzená smluvní cena",
    "cases.payment_application_and_reconciliation.step.contract.title": "Potvrďte smluvní stav",
    "cases.payment_application_and_reconciliation.step.contract.what": "Potvrďte aktuální smluvní cenu, každou odsouhlasenou změnu a podmínky zádržného a plateb, aby žádost stála na částce, na které se obě strany skutečně shodly.",
    "cases.payment_application_and_reconciliation.step.contract.why": "Žádost počítaná ze zastaralé částky, ještě před zahrnutím odsouhlasených změn, se rovnou vrátí. Vyjít ze skutečného smluvního stavu je to, co ji nechá potvrdit bez boje.",
    "cases.payment_application_and_reconciliation.step.reconcile.in.application": "Žádost o platbu",
