    "cases.plan_repetitive_work_with_takt_and_line_of_balance.step.takt-time.why": "Stálý takt brání tomu, aby si profese vzájemně překážely, a zpoždění zviditelní hned v den, kdy nastane, ne až o měsíc později.",
    "cases.plan_repetitive_work_with_takt_and_line_of_balance.step.zones.in.layout": "Půdorysy",
