    "cases.plan_repetitive_work_with_takt_and_line_of_balance.step.zones.what": "Rozdělte budovu na zóny nebo podlaží a definujte činnosti, které se v každé z nich opakují.",
    "cases.plan_repetitive_work_with_takt_and_line_of_balance.step.zones.why": "Opakující se práce plyne jen tehdy, když jsou zóny rovnoměrné a sled je všude stejný. To je základ pro taktový plán.",
    "cases.plan_repetitive_work_with_takt_and_line_of_balance.title": "Plánování opakujících se prací pomocí taktu a liniového harmonogramu",
    "cases.prepare_a_method_statement_and_risk_assessment.desc": "Zpracujte technologický postup a hodnocení rizik pro balík prací dříve, než začne, popište bezpečný postup, určete nebezpečí a opatření, přiřaďte odpovědnosti, nechte ho zkontrolovat a vydat a zpřístupněte ho na stavbě.",
    "cases.prepare_a_method_statement_and_risk_assessment.step.available.in.approved": "Schválený RAMS",
    "cases.prepare_a_method_statement_and_risk_assessment.step.available.in.crew": "Realizační četa",
    "cases.prepare_a_method_statement_and_risk_assessment.step.available.out.briefed": "Proškolená četa",
    "cases.prepare_a_method_statement_and_risk_assessment.step.available.out.filed": "RAMS v souborech projektu",
    "cases.prepare_a_method_statement_and_risk_assessment.step.available.title": "Zpřístupněte ho na stavbě",
    "cases.prepare_a_method_statement_and_risk_assessment.step.available.what": "Uložte vydaný RAMS do souborů projektu, kde na něj dosáhne četa i případný kontrolor, a proškolte četu dříve, než balík prací začne.",
    "cases.prepare_a_method_statement_and_risk_assessment.step.available.why": "RAMS zamčený v kanceláři nikoho nechrání. Aktuální verze na stavbě, se kterou je četa seznámena, z něj dělá pracovní dokument a dokazuje, že práce byla naplánována bezpečně.",
    "cases.prepare_a_method_statement_and_risk_assessment.step.hazards.in.method": "Technologický postup",
    "cases.prepare_a_method_statement_and_risk_assessment.step.hazards.in.steps": "Pracovní kroky",
    "cases.prepare_a_method_statement_and_risk_assessment.step.hazards.out.controls": "Opatření a hodnocení rizik",
    "cases.prepare_a_method_statement_and_risk_assessment.step.hazards.out.hazards": "Seznam nebezpečí",
    "cases.prepare_a_method_statement_and_risk_assessment.step.hazards.title": "Určete nebezpečí a opatření",
    "cases.prepare_a_method_statement_and_risk_assessment.step.hazards.what": "Projděte každý krok a vypište nebezpečí, která vytváří, poté ke každému stanovte opatření a ohodnoťte riziko před opatřením a po něm, aby byla míra nebezpečí jasná.",
    "cases.prepare_a_method_statement_and_risk_assessment.step.hazards.why": "Hodnocení rizik je místo, kde prokážete, že postup je bezpečný, ne jen proveditelný. Ohodnocení rizika před opatřeními a po nich přesně ukáže, proč tam každé opatření je a co se stane bez něj.",
    "cases.prepare_a_method_statement_and_risk_assessment.step.method.in.drawings": "Výkresy a rozmístění",
    "cases.prepare_a_method_statement_and_risk_assessment.step.method.in.package": "Rozsah balíku prací",
    "cases.prepare_a_method_statement_and_risk_assessment.step.method.out.method": "Technologický postup",
    "cases.prepare_a_method_statement_and_risk_assessment.step.method.out.sequence": "Sled prací",
    "cases.prepare_a_method_statement_and_risk_assessment.step.method.title": "Popište bezpečný postup",
    "cases.prepare_a_method_statement_and_risk_assessment.step.method.what": "Popište, jak se balík prací skutečně provede krok za krokem, sled, stroje a zařízení, přístup a zúčastněné lidi, srozumitelným jazykem, kterým se četa dokáže řídit.",
    "cases.prepare_a_method_statement_and_risk_assessment.step.method.why": "Technologický postup mění vágní plán v dohodnutý způsob práce, ke kterému se každý přihlásí. Když je sled zapsaný, celá četa pracuje podle stejné představy, místo aby improvizovala.",
    "cases.prepare_a_method_statement_and_risk_assessment.step.responsibilities.in.controls": "Kontrolní opatření",
    "cases.prepare_a_method_statement_and_risk_assessment.step.responsibilities.in.team": "Tým stavby a role",
    "cases.prepare_a_method_statement_and_risk_assessment.step.responsibilities.out.matrix": "Matice odpovědností",
    "cases.prepare_a_method_statement_and_risk_assessment.step.responsibilities.out.owners": "Přiřazení odpovědní pracovníci",
    "cases.prepare_a_method_statement_and_risk_assessment.step.responsibilities.title": "Přiřaďte odpovědnosti",
    "cases.prepare_a_method_statement_and_risk_assessment.step.responsibilities.what": "Určete, kdo je odpovědný za každé opatření a každou kontrolu, vedoucího, pověřenou osobu pro zdvihací operace, poskytovatele první pomoci, aby každá povinnost v plánu měla svého nositele.",
    "cases.prepare_a_method_statement_and_risk_assessment.step.responsibilities.why": "Opatření bez přiřazeného jména je opatření, které nikdo neudělá. Přiřazení odpovědnosti je to, co promění papírování v něco, co se na stavbě skutečně stane.",
    "cases.prepare_a_method_statement_and_risk_assessment.step.review.in.rams": "Návrh RAMS",
    "cases.prepare_a_method_statement_and_risk_assessment.step.review.in.reviewer": "Odpovědný vedoucí",
    "cases.prepare_a_method_statement_and_risk_assessment.step.review.out.approved": "Schválený RAMS",
    "cases.prepare_a_method_statement_and_risk_assessment.step.review.out.revision": "Označení a revize",
    "cases.prepare_a_method_statement_and_risk_assessment.step.review.title": "Zkontrolujte a vydejte",
    "cases.prepare_a_method_statement_and_risk_assessment.step.review.what": "Odešlete RAMS ke kontrole odpovědnému vedoucímu, zaznamenejte jeho připomínky a poté vydejte schválenou verzi s jasným označením a revizí, aby existovala jedna aktuální kopie.",
    "cases.prepare_a_method_statement_and_risk_assessment.step.review.why": "Kontrola zachytí mezery dříve, než práce začne, ne až po incidentu. Sledované vydání a revize znamená, že četa nikdy nepracuje podle starého nebo neschváleného postupu.",
    "cases.prepare_a_method_statement_and_risk_assessment.title": "Příprava technologického postupu a hodnocení rizik",
    "cases.prepare_an_interim_payment_application.desc": "Sestavte měsíční průběžnou žádost o platbu: změřte dosud provedené práce, oceňte je oproti smluvní ceně plus odsouhlaseným změnám, uplatněte zádržné a vydejte žádost s podklady, aby se potvrdila v plné výši.",
    "cases.prepare_an_interim_payment_application.step.issue.in.breakdown": "Změřený rozpad",
    "cases.prepare_an_interim_payment_application.step.issue.in.net": "Čistá splatná částka",
    "cases.prepare_an_interim_payment_application.step.issue.in.retention": "Výpočet zádržného",
    "cases.prepare_an_interim_payment_application.step.issue.out.application": "Podaná žádost",
    "cases.prepare_an_interim_payment_application.step.issue.out.backup": "Balík podkladů",
    "cases.prepare_an_interim_payment_application.step.issue.title": "Vydejte žádost s podklady",
    "cases.prepare_an_interim_payment_application.step.issue.what": "Vytvořte žádost se změřeným rozpadem, přehledem změn a výpočtem zádržného v příloze a podejte ji dříve, než se perioda uzavře, aby dorazila v rámci platebních podmínek.",
    "cases.prepare_an_interim_payment_application.step.issue.why": "Žádost podaná pozdě nebo bez podkladů je ta, kterou pod časovým tlakem seškrtají. Úplné doklady včas jsou to, co ji nechá potvrdit v plné výši, místo aby se doháněla.",
    "cases.prepare_an_interim_payment_application.step.measure.in.boq": "Položky BOQ",
    "cases.prepare_an_interim_payment_application.step.measure.in.cutoff": "Rozhodné datum",
    "cases.prepare_an_interim_payment_application.step.measure.in.works": "Provedené práce",
    "cases.prepare_an_interim_payment_application.step.measure.out.measured": "Změřené výměry",
    "cases.prepare_an_interim_payment_application.step.measure.out.percent": "Procento dokončení",
