    "cases.run_reactive_fm_service_after_handover.step.request.why": "Poruchu, která není zaevidována k zařízení, nelze sledovat v trendech ani doložit, že byla opravena. Navázání na zařízení hned od prvního hlášení vám později ukáže, která zařízení stále selhávají a zda byla dodržena lhůta pro reakci.",
    "cases.run_reactive_fm_service_after_handover.step.verify.in.repair": "Dokončená oprava",
    "cases.run_reactive_fm_service_after_handover.step.verify.in.request": "Otevřený servisní požadavek",
    "cases.run_reactive_fm_service_after_handover.step.verify.out.check": "Ověřená oprava",
    "cases.run_reactive_fm_service_after_handover.step.verify.out.closed": "Uzavřený požadavek",
    "cases.run_reactive_fm_service_after_handover.step.verify.out.history": "Historie údržby",
    "cases.run_reactive_fm_service_after_handover.step.verify.title": "Uzavřete ověřovací kontrolou",
    "cases.run_reactive_fm_service_after_handover.step.verify.what": "Než práci označíte za hotovou, proveďte krátkou ověřovací kontrolu, že je porucha skutečně odstraněna a zařízení je zpět v předepsaném stavu, a doložte to fotkou. Teprve pak požadavek uzavřete.",
    "cases.run_reactive_fm_service_after_handover.step.verify.why": "Práce uzavřená jen na základě důvěry se příští týden zase otevře. Rychlá ověřovací kontrola zajistí, že uzavřeno znamená opraveno, a dá správci čistou historii údržby zařízení.",
    "cases.run_reactive_fm_service_after_handover.title": "Proveďte reaktivní servis FM po předání",
    "cases.run_the_site_day.desc": "Pořádně uzavřete den: zapište deník, zaúčtujte hodiny lidí a strojů, nahrajte fotky a zaznamenejte bezpečnostní pozorování, aby den přežil jako důkaz, o který se můžete opřít.",
    "cases.run_the_site_day.step.diary.in.crews": "Čety a návštěvy",
    "cases.run_the_site_day.step.diary.in.progress": "Provedené práce a zdržení",
    "cases.run_the_site_day.step.diary.in.weather": "Počasí a podmínky",
    "cases.run_the_site_day.step.diary.out.entry": "Datovaný zápis do deníku",
    "cases.run_the_site_day.step.diary.out.record": "Soudobý záznam",
    "cases.run_the_site_day.step.diary.title": "Napište stavební deník",
    "cases.run_the_site_day.step.diary.what": "Poznamenejte počasí, čety a návštěvy na stavbě, práce provedené v každé oblasti a jakékoli zdržení, jako je pozdní dodávka nebo naražení na inženýrskou síť. Zapsáno týž den je to váš soudobý záznam.",
    "cases.run_the_site_day.step.diary.why": "Zápis do deníku pořízený týž den má důkazní váhu, jakou rekonstrukce sepsaná o měsíce později nikdy mít nebude. Když přijde nárok za zdržení nebo spor, je to první záznam, po kterém obchodní tým sáhne.",
    "cases.run_the_site_day.step.hours.in.codes": "Nákladové kódy",
    "cases.run_the_site_day.step.hours.in.crews": "Čety na stavbě",
    "cases.run_the_site_day.step.hours.in.plant": "Pronajaté stroje",
    "cases.run_the_site_day.step.hours.out.cost": "Náklady dle nákladových kódů",
    "cases.run_the_site_day.step.hours.out.hours": "Zaúčtované hodiny lidí a strojů",
    "cases.run_the_site_day.step.hours.title": "Zaúčtujte hodiny lidí a strojů",
    "cases.run_the_site_day.step.hours.what": "Zaúčtujte na tento projekt hodiny každé čety a každého stroje, označené správným nákladovým kódem, aby náklady dopadly tam, kde je rozpočet očekává.",
    "cases.run_the_site_day.step.hours.why": "Hodiny zachycené, dokud je směna čerstvá, můžete fakturovat, započítat do rozpočtu a porovnat s výkonem. Zrekonstruované na konci měsíce se změní v odhad a odhadování u práce je místo, kde marže tiše mizí.",
    "cases.run_the_site_day.step.photos.in.entry": "Zápis v deníku",
    "cases.run_the_site_day.step.photos.in.shots": "Fotky pořízené na stavbě",
    "cases.run_the_site_day.step.photos.out.dated": "Datované fotky postupu",
    "cases.run_the_site_day.step.photos.out.gallery": "Označená galerie stavby",
    "cases.run_the_site_day.step.photos.title": "Pořiďte fotky ze stavby",
    "cases.run_the_site_day.step.photos.what": "Přidejte fotky dne ze souborů projektu. Označí se jako snímky ze stavby a objeví se v galerii, v pásu dne a v zápise deníku, datované a seřazené.",
    "cases.run_the_site_day.step.photos.why": "Datovaná fotka ukončí spor, který slova jen protahují. Dokládá postup, zachycuje stav, který jste převzali, a zaznamená výztuž nebo rozvody dřív, než je betonáž nebo sádrokarton navždy schová.",
    "cases.run_the_site_day.step.safety.in.hazard": "Riziko nebo skoronehoda",
    "cases.run_the_site_day.step.safety.in.talk": "Bezpečnostní školení",
    "cases.run_the_site_day.step.safety.out.observation": "Zaznamenané pozorování",
    "cases.run_the_site_day.step.safety.out.trend": "Data o trendech bezpečnosti",
    "cases.run_the_site_day.step.safety.title": "Zaznamenejte bezpečnostní pozorování",
    "cases.run_the_site_day.step.safety.what": "Zaznamenejte každé zjištěné riziko, nahlášenou skoronehodu nebo správný postup hodný opakování a uveďte, kdo odpovídá za dořešení. Zde také zaznamenejte bezpečnostní školení a kdo se ho zúčastnil.",
    "cases.run_the_site_day.step.safety.why": "Co se zaznamená, to se řeší, a trend napříč mnoha drobnými zápisy je to, co vás varuje před vážnou událostí. Skoronehoda sepsaná dnes je často úraz, kterému příští týden předejdete.",
    "cases.run_the_site_day.title": "Zvládněte den na stavbě",
    "cases.run_the_submittals_register.desc": "Zaevidujte dílenské výkresy a předkládané dokumenty, ověřte je vůči specifikaci, vydejte je k připomínkování a označte vše po termínu dřív, než to zastaví nákup.",
    "cases.run_the_submittals_register.step.attach-spec.in.item": "Zaevidovaný dokument",
    "cases.run_the_submittals_register.step.attach-spec.in.spec": "Dokument specifikace",
    "cases.run_the_submittals_register.step.attach-spec.out.baseline": "Podklad pro posouzení",
    "cases.run_the_submittals_register.step.attach-spec.out.clause": "Připojený článek specifikace",
