    "cases.run_the_submittals_register.step.attach-spec.what": "Z QMS připojte článek specifikace, vůči kterému se dokument ověřuje.",
    "cases.run_the_submittals_register.step.attach-spec.why": "Posuzovatel potřebuje mít specifikaci vedle dokumentu, jinak je schválení jen názor. Zároveň to vyřeší pozdější spory o tom, co bylo vlastně předepsáno.",
    "cases.run_the_submittals_register.step.issue-review.in.package": "Balík dokumentů",
    "cases.run_the_submittals_register.step.issue-review.in.reviewer": "Posuzovatel projektu",
    "cases.run_the_submittals_register.step.issue-review.out.comments": "Připomínky z posouzení",
    "cases.run_the_submittals_register.step.issue-review.out.status": "Stav posouzení",
    "cases.run_the_submittals_register.step.issue-review.title": "Vydejte k posouzení",
    "cases.run_the_submittals_register.step.issue-review.what": "V modulu Korespondence vydejte dokument k posouzení a zaznamenejte vrácený stav: schváleno, schváleno s připomínkami nebo zamítnuto.",
    "cases.run_the_submittals_register.step.issue-review.why": "Vrácený stav je impulzem k objednání nebo opětovnému předložení, takže musí být zaznamenán u dané položky. Ústní ano nákup neuvolní.",
    "cases.run_the_submittals_register.step.log.in.drawings": "Dílenské výkresy",
    "cases.run_the_submittals_register.step.log.in.submittals": "Technické podklady",
