    "cases.track_an_opportunity_from_enquiry_to_tender.step.opportunity.out.stage": "Fáze a pravděpodobnost",
    "cases.track_an_opportunity_from_enquiry_to_tender.step.opportunity.title": "Otevřete a sledujte příležitost",
    "cases.track_an_opportunity_from_enquiry_to_tender.step.opportunity.what": "Otevřete příležitost, nastavte její hodnotu, fázi a pravděpodobnost výhry a zaznamenávejte k ní každý hovor a schůzku.",
    "cases.track_an_opportunity_from_enquiry_to_tender.step.opportunity.why": "Trychtýř, který nevidíte, nedokážete prognózovat. Fáze a pravděpodobnost vám řeknou, co urgovat a na co obsadit lidi.",
    "cases.track_an_opportunity_from_enquiry_to_tender.step.tender.in.project": "Aktivní projekt",
