    "cases.validate_estimate.step.validate.out.issues": "Propojené chyby a varování",
    "cases.validate_estimate.step.validate.out.score": "Semaforové hodnocení",
    "cases.validate_estimate.step.validate.title": "Spusťte validační pravidla",
    "cases.validate_estimate.step.validate.what": "Spusťte sady pravidel na výkaz a přečtěte semaforový výsledek. Každá chyba a varování je propojena s přesnou položkou, takže můžete skočit na problematický řádek a opravit příčinu, ne příznak.",
    "cases.validate_estimate.step.validate.why": "Chybějící výměry, nulové ceny, duplicitní řádky a sazby mimo rozumné rozpětí se dnes opraví levně a po vydání se vysvětlují nepříjemně. Hodnocení je váš poctivý signál jít, nebo nejít.",
    "cases.validate_estimate.title": "Zkontrolujte rozpočet, než ho odešlete",
    "cases.verify_as_built_against_the_model_with_a_scan.desc": "Načtěte sken stavby, překryjte projektový model, abyste odhalili, kde se stavba odchýlila od modelu, a založte kontrolu všude tam, kde skutečné provedení leží mimo toleranci.",
    "cases.verify_as_built_against_the_model_with_a_scan.step.inspect.in.deviation": "Změřené odchylky",
    "cases.verify_as_built_against_the_model_with_a_scan.step.inspect.in.tolerance": "Meze tolerance",
    "cases.verify_as_built_against_the_model_with_a_scan.step.inspect.out.inspection": "Založená kontrola",
    "cases.verify_as_built_against_the_model_with_a_scan.step.inspect.out.record": "Záznam odchylky",
    "cases.verify_as_built_against_the_model_with_a_scan.step.inspect.title": "Založte kontrolu při překročení tolerance",
    "cases.verify_as_built_against_the_model_with_a_scan.step.inspect.what": "Tam, kde stavba leží mimo povolenou toleranci, založte kontrolu k danému místu s připojenou změřenou odchylkou a fotkou nebo výřezem skenu.",
    "cases.verify_as_built_against_the_model_with_a_scan.step.inspect.why": "Odchylka, kterou nikdo nezaznamená, se pohřbí ve chvíli, kdy ji další řemeslo zakryje. Kontrola zařadí práci mimo toleranci na seznam, který musí být vyřešen, než se zakryje.",
    "cases.verify_as_built_against_the_model_with_a_scan.step.overlay.in.model": "Projektový model",
    "cases.verify_as_built_against_the_model_with_a_scan.step.overlay.in.scan": "Registrovaný sken",
    "cases.verify_as_built_against_the_model_with_a_scan.step.overlay.out.deviation": "Změřené odchylky",
    "cases.verify_as_built_against_the_model_with_a_scan.step.overlay.out.overlay": "Překryv modelu a skenu",
    "cases.verify_as_built_against_the_model_with_a_scan.step.overlay.title": "Překryjte model na sken",
    "cases.verify_as_built_against_the_model_with_a_scan.step.overlay.what": "Načtěte projektový model do stejného pohledu jako mračno bodů a projděte překryv, přičemž hledáte, kde postavený povrch vyčnívá před modelovaný prvek nebo zaostává za ním.",
    "cases.verify_as_built_against_the_model_with_a_scan.step.overlay.why": "Sken je nezvratná pravda o tom, co bylo skutečně postaveno. Položení modelu přes něj promění mlhavý pocit, že něco není v pořádku, ve změřenou odchylku, na kterou lze ukázat.",
    "cases.verify_as_built_against_the_model_with_a_scan.step.scan.in.cloud": "Soubor mračna bodů",
    "cases.verify_as_built_against_the_model_with_a_scan.step.scan.in.coords": "Projektové souřadnice",
    "cases.verify_as_built_against_the_model_with_a_scan.step.scan.out.aligned": "Sken v projektové síti",
    "cases.verify_as_built_against_the_model_with_a_scan.step.scan.out.scan": "Registrovaný sken",
    "cases.verify_as_built_against_the_model_with_a_scan.step.scan.title": "Načtěte sken stavby",
    "cases.verify_as_built_against_the_model_with_a_scan.step.scan.what": "Načtěte do prohlížeče laserový sken nebo fotogrammetrické mračno bodů skutečně provedené oblasti a nastavte jej na projektové souřadnice, aby přistálo tam, kde ho model očekává.",
    "cases.verify_as_built_against_the_model_with_a_scan.step.scan.why": "Sken vztažený ke špatnému počátku nesedí s ničím a každá odchylka se jeví jako falešná. Umístit zaměření nejprve do projektové sítě je to, co učiní celé porovnání důvěryhodným.",
    "cases.verify_as_built_against_the_model_with_a_scan.title": "Ověřte skutečné provedení proti modelu pomocí skenu",
